from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
import json
import os
import logging

logging.basicConfig(level=logging.INFO)

PROJECT_ID = os.getenv("GCP_PROJECT") or os.getenv("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.getenv("PUBSUB_TOPIC", "processed-files")

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    data = cloud_event.data
    bucket_name = data.get("bucket")
    file_name = data.get("name")
    generation = data.get("generation")

    if not bucket_name or not file_name:
        logging.error("Missing bucket or file name in event")
        return

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    try:
        content = blob.download_as_text()
    except Exception:
        content = None

    record = {
        "bucket": bucket_name,
        "file_name": file_name,
        "generation": generation,
        "content": content,
        "metadata": {
            k: v for k, v in data.items() if k not in {"bucket", "name", "generation"}
        },
        "processed_at": firestore.SERVER_TIMESTAMP,
    }

    doc_id = f"{bucket_name}:{file_name}:{generation or 'latest'}"
    firestore_client.collection("processed_files").document(doc_id).set(record)

    message = {
        "bucket": bucket_name,
        "file_name": file_name,
        "generation": generation,
        "doc_id": doc_id,
    }

    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    publisher.publish(topic_path, json.dumps(message).encode("utf-8"))

    logging.info("Processed file %s from bucket %s", file_name, bucket_name)